+    )]));
+    if let Some(state) = &model.daemon_state {
+        let level_color = theme.palette.pressure_color(&state.pressure.overall);
+        let policy_color = policy_mode_color(&state.policy_mode, &theme.palette);
+        lines.push(Line::from_spans([
