+#[must_use]
+pub fn styled_status_strip(hints: &[(&str, &str)], accent: PackedRgba) -> Line {
+    let mut spans: Vec<Span<'_>> = Vec::new();
+    for (key, label) in hints {
+        spans.extend(key_hint(key, label, accent));
+    }
+    Line::from_spans(spans)
